use std::collections::HashMap;
use std::sync::atomic::{AtomicUsize, Ordering};

struct ConnectionMetrics {
    bytes_sent: AtomicUsize,
    packets_processed: AtomicUsize,
}

impl Default for ConnectionMetrics {
    fn default() -> Self {
        ConnectionMetrics {
            bytes_sent: AtomicUsize::new(0),
            packets_processed: AtomicUsize::new(0),
        }
    }
}

struct ProxySession {
    metrics: HashMap<u32, ConnectionMetrics>,
    total_connections: AtomicUsize,
}

impl ProxySession {
    fn new() -> Self {
        ProxySession {
            metrics: HashMap::new(),
            total_connections: AtomicUsize::new(0),
        }
    }

    fn record_connection_start(&mut self, address: u32) {
        if !self.metrics.contains_key(&address) {
            let metrics = ConnectionMetrics::default();
            self.metrics.insert(address, metrics);
        }
        self.total_connections.fetch_add(1, Ordering::SeqCst);
    }

    fn shape_traffic(&mut self, address: u32, data_size: usize) {
        if let Some(metrics) = self.metrics.get_mut(&address) {
            metrics.bytes_sent.fetch_add(data_size, Ordering::SeqCst);
            metrics.packets_processed.fetch_add(1, Ordering::SeqCst);
        }
    }

    fn get_summary(&self) -> String {
        let mut total_bytes: usize = 0;
        for metrics in self.metrics.values() {
            total_bytes += metrics.bytes_sent.load(Ordering::SeqCst);
        }
        format!("Total Connections: {}", self.total_connections.load(Ordering::SeqCst))
    }
}

fn main() {
    let mut session = ProxySession::new();
    session.record_connection_start(192_168_0_1);
    session.shape_traffic(192_168_0_1, 512);

    session.record_connection_start(10_0_0_5);
    session.shape_traffic(10_0_0_5, 1024);

    println!("nProxy Session Summary: {}", session.get_summary());
}

use std::collections::HashMap;

struct SerializerBenchmark {
    name: String,
    data: HashMap<String, u32>,
}

impl SerializerBenchmark {
    fn new(name: &str, data: HashMap<String, u32>) -> Self {
        SerializerBenchmark {
            name: name.to_string(),
            data,
        }
    }

    fn run_test(&self) -> Result<(), String> {
        if self.data.is_empty() {
            return Err(format!("No data found for {}", self.name));
        }
        let total: u32 = self.data.values().sum();
        println!("Successfully processed {} records. Total value: {}", self.data.len(), total);
        Ok(()) 
    }
}

fn main() {
    let mut data1 = HashMap::new();
    data1.insert("key_a".to_string(), 10);
    data1.insert("key_b".to_string(), 20);

    let serializer1 = SerializerBenchmark::new("JSON", data1);
    match serializer1.run_test() {
        Ok(_) => println!("Test 1 completed successfully."),
        Err(e) => eprintln!("Test 1 failed: {}", e),
    }

    let mut data2 = HashMap::new();
    data2.insert("key_c".to_string(), 5);

    let serializer2 = SerializerBenchmark::new("Binary", data2);
    if let Err(e) = serializer2.run_test() { 
        eprintln!("Test 2 caught expected error: {}", e)
    }
}

use std::collections::HashMap;

struct ElfBinary {
    name: String,
    metadata: HashMap<String, u32>,
}

impl ElfBinary {
    fn new(name: &str) -> Self {
        ElfBinary {
            name: name.to_string(),
            metadata: HashMap::with_capacity(4),
        }
    }

    fn validate(&self, required_key: &str, expected_value: u32) -> bool {
        if !self.metadata.contains_key(required_key) {
            return false;
        }

        let actual = self.metadata.get(required_key);

        match actual {
            Some(&v) => v == expected_value,
            None => false,
        }
    }
}

fn load_and_check_module(binary_name: &str, key: &str, expected: u32) -> bool {
    let mut binary = ElfBinary::new(binary_name);
    binary.metadata.insert(key.to_string(), 0x12345678); // Added some data to avoid immediate failure if we were testing real usage, though main() doesn't populate it.
    binary.validate(key, expected)
}

fn main() {
    let module1_ok = load_and_check_module("kernel_loader", "magic_number", 0xDEADBEEF);
    println!("Module 1 Check Passed: {}", module1_ok);

    let module2_fail = load_and_check_module("bad_binary", "api_version", 99);
    println!("Module 2 Check Passed: {}", module2_fail);
}

use std::fs::File;
use std::io::{self, BufReader, BufRead};

fn main() -> io::Result<()> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: <logfile_path>");
        return Ok(());
    }

    let file_path = &args[1];
    let target_string = "ERROR";
    let mut count = 0;

    let file = File::open(file_path)?;
    let reader = BufReader::new(file);

    for line in reader.lines() {
        match line {
            Ok(l) => {
                if l.contains(target_string) {
                    count += 1;
                }
            }
            Err(e) => {
                eprintln!("Error reading line: {}", e);
            }
        }
    }

    println!("Total lines containing \"{}\": {}", target_string, count);
    Ok(())
}

use std::collections::{HashMap, VecDeque, HashSet};

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
struct NodeId(usize);

type AdjacencyList = HashMap<NodeId, Vec<NodeId>>;

fn bfs_query(graph: &AdjacencyList, start_node: &NodeId) -> Vec<NodeId> {
    let mut visited = HashSet::new();
    let mut queue: VecDeque<NodeId> = VecDeque::new();
    let mut result = Vec::new();

    visited.insert(start_node.clone());
    queue.push_back(start_node.clone());

    while let Some(current) = queue.pop_front() {
        result.push(current.clone());

        if let Some(neighbors) = graph.get(&current) {
            for neighbor in neighbors {
                if !visited.contains(neighbor) {
                    visited.insert(neighbor.clone());
                    queue.push_back(neighbor.clone());
                }
            }
        }
    }
    result
}

fn dfs_query(graph: &AdjacencyList, start_node: &NodeId) -> Vec<NodeId> {
    let mut visited = HashSet::new();
    let mut stack: Vec<NodeId> = Vec::new();
    let mut result = Vec::new();

    visited.insert(start_node.clone());
    stack.push(start_node.clone());

    while let Some(current) = stack.pop() {
        result.push(current.clone());

        if let Some(neighbors) = graph.get(&current) {
            for neighbor in neighbors.iter().rev() {
                if !visited.contains(neighbor) {
                    visited.insert(neighbor.clone());
                    stack.push(neighbor.clone());
                }
            }
        }
    }
    result
}

fn main() {
    let mut graph: AdjacencyList = HashMap::new();
    graph.insert(NodeId(1), vec![NodeId(2), NodeId(3)]);
    graph.insert(NodeId(2), vec![NodeId(4)]);
    graph.insert(NodeId(3), vec![NodeId(5)]);
    graph.insert(NodeId(4), vec![NodeId(6)]);
    graph.insert(NodeId(5), vec![]);
    graph.insert(NodeId(6), vec![]);

    let start = NodeId(1);

    let bfs_result = bfs_query(&graph, &start);
    println!("BFS Traversal Order: {:?}", bfs_result);

    let dfs_result = dfs_query(&graph, &start);
    println!("DFS Traversal Order: {:?}", dfs_result);
}
